/* ============================================================
   State — load from localStorage or fall back to defaults.
   Separate try/catch guards against corrupted JSON.
   ============================================================ */
const State = {
  stories: (() => { try { const v = localStorage.getItem('ua_stories'); return v ? JSON.parse(v) : [...DEFAULT_STORIES]; } catch { return [...DEFAULT_STORIES]; } })(),
  tips:    (() => { try { const v = localStorage.getItem('ua_tips');    return v ? JSON.parse(v) : [...DEFAULT_TIPS];    } catch { return [...DEFAULT_TIPS];    } })(),
  terms:   (() => { try { const v = localStorage.getItem('ua_terms');   return v ? JSON.parse(v) : [...DEFAULT_TERMS];  } catch { return [...DEFAULT_TERMS];  } })(),
  save: {
    stories: () => { try { localStorage.setItem('ua_stories', JSON.stringify(State.stories)); } catch(e) { console.warn('Storage full', e); } },
    tips:    () => { try { localStorage.setItem('ua_tips',    JSON.stringify(State.tips));    } catch(e) { console.warn('Storage full', e); } },
    terms:   () => { try { localStorage.setItem('ua_terms',   JSON.stringify(State.terms));   } catch(e) { console.warn('Storage full', e); } }
  }
};

/* ============================================================
   Pure utilities
   ============================================================ */
function escHtml(str) {
  if (str == null) return '';
  return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
}
function randomItem(arr) { return arr[Math.floor(Math.random() * arr.length)]; }
function randomStory()   { return randomItem(State.stories); }
function formatDate(iso) { try { return new Date(iso).toLocaleDateString(undefined, { month:'long', day:'numeric', year:'numeric' }); } catch { return ''; } }
function wordCount(str)  { return str ? str.trim().split(/\s+/).length : 0; }
function readingTime(str){ return Math.max(1, Math.ceil(wordCount(str) / 200)); }
